+                "none"
+            } else {
+                entry.notes.as_str()
+            };
+            out.push_str(&format!(
+                "| {} | {} | {} | {} |\n",
+                entry.ft_command,
+                ntm_command,
+                entry.compat_level.label(),
+                notes,
+            ));
+        }
+
